	v.RegisterStructValidation(UserStructLevelValidation, User{})
}

if files := r.MultipartForm.File[key]; len(files) != 0 {
	return setByMultipartFormFile(value, field, files)
}

if paramsCount := countParams(path); paramsCount > engine.maxParams {
	engine.maxParams = paramsCount
}

if len(r.Files) > 0 {
	return template.Must(template.New("").Delims(r.Delims.Left, r.Delims.Right).Funcs(r.FuncMap).ParseFiles(r.Files...))
}

if r.Glob != "" {
	return template.Must(template.New("").Delims(r.Delims.Left, r.Delims.Right).Funcs(r.FuncMap).ParseGlob(r.Glob))
}

if cfg.OutPath == "" {
	cfg.OutPath = fmt.Sprintf(".%squery%s", string(os.PathSeparator), string(os.PathSeparator))
}

if conds := field.GetConds(); len(conds) > 0 {
	args = append(args, toExpressionInterface(conds...)...)
}

if len(fields) > 0 {
	return NewString("", r.fieldName+"."+strings.Join(fields, ".")).appendBuildOpts(WithoutQuote)
}

if !ok {
	return e, fmt.Errorf("gen: FirstOrInit type mismatch, expected %T, got %T", new(E), result)
}

if !ok {
	return e, fmt.Errorf("gen: FirstOrCreate type mismatch, expected %T, got %T", new(E), result)
}

if model.GormKeywords.FullMatch(m.MethodName) {
	return fmt.Errorf("can not use keyword as method name:%s", m.MethodName)
}

if tableName == nil {
	methods = append(methods, parser.DefaultMethodTableName(b.ModelStructName))
}

if len(method.pkgFiles) == 0 {
	return nil, fmt.Errorf("diy method file not found:%s.%s", method.pkgPath, method.MethodName)
}

if sqlClause := buf.Dump(); strings.TrimSpace(sqlClause) != "" {
	m.Section.members = append(m.Section.members, section{
		Type:  model.SQL,
		Value: strconv.Quote(sqlClause),
	})
}

if err = yaml.NewDecoder(file).Decode(&yamlConfig); err != nil {
	log.Fatalf("parseCmdFromYaml fail %s", err.Error())
	return nil
}

type YamlConfig struct {
	Version  string     `yaml:"version"`  //
	Database *CmdParams `yaml:"database"` //
}

if association.Error == nil {
	association.Error = association.buildCondition().Count(&count).Error
}

if association.Error == nil {
	association.Error = association.buildCondition().Find(out, conds...).Error
}

if conds := tx.Statement.BuildCondition(query, args...); len(conds) > 0 {
	tx.Statement.AddClause(clause.Where{Exprs: conds})
}

if len(whereConds) > 0 {
	tx.Statement.AddClause(clause.Where{Exprs: tx.Statement.BuildCondition(whereConds[0], whereConds[1:]...)})
}

clause.OrderByColumn{
	Column: clause.Column{Table: clause.CurrentTable, Name: clause.PrimaryKey},
}

if c.buckets[bucketID].newestEntry.Before(e.ExpiresAt) {
	c.buckets[bucketID].newestEntry = e.ExpiresAt
}

for ent := c.evictList.Back(); ent != nil; ent = ent.PrevEntry() {
	if now.After(ent.ExpiresAt) {
		continue
	}
	keys = append(keys, ent.Key)
}

for ent := c.evictList.Back(); ent != nil; ent = ent.PrevEntry() {
	if now.After(ent.ExpiresAt) {
		continue
	}
	values = append(values, ent.Value)
}
